__global__ void compute_step_kernel(float* f, float* f_old, float* local_error, int n_inner) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_inner = (N-2) * (N-2);

    if (idx < total_inner) {
        int i = (idx % (N-2)) + 1;
        int j = (idx / (N-2)) + 1;

