        float item_8 = t - f_old[idx_cur];
        f[idx_cur] = t;

        local_error[idx] = item_8 * item_8;
    }
}

__global__ void copy_back_kernel(float* f, float* f_old) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * N;
    if (idx < total) {
        int i = idx % N;
        int j = idx / N;
        if (1 <= j && N-2 >= j && 1 <= i && N-2 >= i) {
            f_old[idx] = f[idx];
        }
    }
}

__global__ void sum_error_kernel(float* local_error, float* global_error, int count) {
    float sum = 0.0f;
